import { readFile, writeFile } from "node:fs/promises";
import { createBucket, put, list } from "@tigrisdata/storage";

async function main() {
  // 1. Read and normalize the trial_id
  const rawTrialId = await readFile("/logs/artifacts/trial_id", "utf-8");
  const trialId = rawTrialId.trim();

  // 2. Build a valid S3 bucket name: lowercase, replace invalid chars with hyphens
  const bucketName = `harbor-tssdk-${trialId}`
    .toLowerCase()
    .replace(/[^a-z0-9.\-]/g, "-");

  console.log(`Using bucket: ${bucketName}`);

  // 3. Create the bucket (ignore "already exists" errors)
  const createResult = await createBucket(bucketName);
  if (createResult.error) {
    const msg = createResult.error.message ?? String(createResult.error);
    if (!msg.toLowerCase().includes("already") && !msg.toLowerCase().includes("exist") && !msg.toLowerCase().includes("owned")) {
      console.error("createBucket error:", createResult.error);
      process.exit(1);
    }
    console.log("Bucket already exists, continuing.");
  } else {
    console.log("Bucket created successfully.");
  }

  // 4. Upload three JSON objects
  const objects = [
    { path: "inbox/msg-1.json", body: JSON.stringify({ id: 1 }) },
    { path: "inbox/msg-2.json", body: JSON.stringify({ id: 2 }) },
    { path: "inbox/msg-3.json", body: JSON.stringify({ id: 3 }) },
  ];

  for (const obj of objects) {
    const putResult = await put(obj.path, obj.body, {
      contentType: "application/json",
      allowOverwrite: true,
      config: { bucket: bucketName },
    });
    if (putResult.error) {
      console.error(`put error for ${obj.path}:`, putResult.error);
      process.exit(1);
    }
    console.log(`Uploaded: ${obj.path}`);
  }

  // 5. List objects with prefix "inbox/" and write names to listing.txt
  const listResult = await list({
    prefix: "inbox/",
    config: { bucket: bucketName },
  });
  if (listResult.error) {
    console.error("list error:", listResult.error);
    process.exit(1);
  }

  const names = (listResult.data?.items ?? []).map((item) => item.name);
  console.log("Listed objects:", names);

  await writeFile("/home/user/tigris-task/listing.txt", names.join("\n") + "\n");
  console.log("Wrote listing.txt");
}

main().catch((err) => {
  console.error("Unexpected error:", err);
  process.exit(1);
});
